// Omit<T, K> = Pick<T, Exclude<keyof T, K>>

// Шаг 1: keyof User
// = 'id' | 'name' | 'email' | 'passwordHash'

// Подставляем:
// Pick<User, Exclude<'id' | 'name' | 'email' | 'passwordHash', 'passwordHash'>>

// Exclude<'id' | 'name' | 'email' | 'passwordHash', 'passwordHash'>

// Дистрибутивное вычисление:
// 'id' extends 'passwordHash' ? never : 'id'                → 'id'
// 'name' extends 'passwordHash' ? never : 'name'            → 'name'
// 'email' extends 'passwordHash' ? never : 'email'          → 'email'
// 'passwordHash' extends 'passwordHash' ? never : ...        → never

// Результат: 'id' | 'name' | 'email'

// Pick<User, 'id' | 'name' | 'email'>

// Mapped type: для каждого ключа из 'id' | 'name' | 'email'
// берём соответствующий тип из User

type PublicUser = {
  id: number
  name: string
  email: string
}

// passwordHash исключён — цель достигнута!
